const SESSION_ID = 'YOUR_SESSION_ID';
const MY_PHONE = 'YOUR_PHONE';

const rows = $input.all();
const today = new Date().toISOString().split('T')[0];

const todaySales = rows.filter(r => {
  const d = r.json.Date || r.json.date || '';
  return d.startsWith(today);
});

if (todaySales.length === 0) {
  const message = `Daily Sales Report (${today})\n\nNo sales recorded today.`;
  return [{ json: { session_id: SESSION_ID, chat_id: MY_PHONE + '@c.us', message } }];
}

let totalRevenue = 0;
const productCounts = {};

for (const sale of todaySales) {
  const amount = parseFloat(sale.json.Amount || sale.json.amount || 0);
  const product = sale.json.Product || sale.json.product || 'Unknown';
  totalRevenue += amount;
  productCounts[product] = (productCounts[product] || 0) + 1;
}

const topProduct = Object.entries(productCounts)
  .sort((a, b) => b[1] - a[1])[0];

const message = `Daily Sales Report (${today})\n\nOrders: ${todaySales.length}\nRevenue: $${totalRevenue.toFixed(2)}\nTop product: ${topProduct[0]} (${topProduct[1]} sold)\n\nKeep it up!`;

return [{
  json: {
    session_id: SESSION_ID,
    chat_id: MY_PHONE + '@c.us',
    message: message
  }
}];
